// src/utils/helpers.js

export const ROLES = {
  CHIEF_ADMIN: 'Chief Admin',
  REGULATORY_ADMIN: 'Regulatory Admin',
  OPERATIONAL_ADMIN: 'Operational Admin',
  STAFF: 'Staff'
};

export const JOB_ROLES = ['ST', 'TT', 'CCS', 'CCO', 'CCA', 'FFM', 'FFS', 'FFA'];
export const INCOME_TYPES = ['UBI 1', 'UBI 2', 'Remuneration'];

export const formatCurrency = (amount) => {
  if (!amount && amount !== 0) return '0 đ';
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount);
};

export const formatDate = (dateString) => {
  if (!dateString) return '';
  const date = new Date(dateString);
  return date.toLocaleString('vi-VN');
};

export const calculatePerformanceRating = (progress, deadline, completedDate) => {
  const isCompleted = progress === 100;
  const deadLineDate = new Date(deadline);
  const finishDate = completedDate ? new Date(completedDate) : new Date();
  
  // Tính khoảng cách ngày
  const diffTime = finishDate - deadLineDate;
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

  if (isCompleted && diffDays <= -1) return "Xuất sắc";
  if (progress >= 90 && diffDays <= 0) return "Tốt";
  if (progress >= 70 && progress <= 85 && diffDays <= 0) return "Cần điều chỉnh";
  if (progress >= 60 && progress <= 70 && diffDays >= 3) return "Cảnh cáo";
  if (!isCompleted && diffDays > 0) return "Kỷ luật";
  
  return "Đang thực hiện";
};
